mapper.select:
/** CmmtSurveyQuestionDao.select */
select

from
	cmmt_survey_question
where
	survey_id = #{surveyId}
	and question_id = #{questionId}

mapper.delete:
/** CmmtSurveyQuestionDao.deleteList_surveyId */
delete from
	cmmt_survey_question
where
	survey_id = #{surveyId}

mapper.insert:
/** CmmtSurveyQuestionDao.insertList */
insert into cmmt_survey_question (
	 survey_id
	,question_id
	,question_no
	,question_type
	,required
	,question_cn
) values

	(
		 #{item.surveyId}
		,#{item.questionId}
		,#{item.questionNo}
		,#{item.questionType}
		,#{item.required}
		,#{item.questionCn}
	)
